css:
.loader {
  width: 175px;
  height: 80px;
  display: block;
  background-image: radial-gradient(circle 25px at 25px 25px, #ffffff 100%, transparent 0), radial-gradient(circle 50px at 50px 50px, #ffffff 100%, transparent 0), radial-gradient(circle 25px at 25px 25px, #ffffff 100%, transparent 0), linear-gradient(#ffffff 50px, transparent 0);
  background-size: 50px 50px, 100px 76px, 50px 50px, 120px 40px;
  background-position: 0 30px, 37px 0, 122px 30px, 25px 40px;
  background-repeat: no-repeat;
  position: relative;
  box-sizing: border-box;
}
.loader::before,
.loader::after {
  content: "";
  position: absolute;
  border-radius: 50%;
  background-color: #ff3d00;
  background-repeat: no-repeat;
  box-sizing: border-box;
}
.loader::before {
  left: 60px; bottom: 18px; width: 36px; height: 36px;
  background-image: radial-gradient(circle 8px at 18px 18px, #ffffff 100%, transparent 0), radial-gradient(circle 4px at 18px 0, #ffffff 100%, transparent 0), radial-gradient(circle 4px at 0 18px, #ffffff 100%, transparent 0), radial-gradient(circle 4px at 36px 18px, #ffffff 100%, transparent 0), radial-gradient(circle 4px at 18px 36px, #ffffff 100%, transparent 0);
  animation: reelSpin 3s linear infinite;
}
.loader::after {
  left: 94px; bottom: 15px; width: 24px; height: 24px;
  background-image: radial-gradient(circle 5px at 12px 12px, #ffffff 100%, transparent 0), radial-gradient(circle 3px at 12px 0, #ffffff 100%, transparent 0), radial-gradient(circle 3px at 0 12px, #ffffff 100%, transparent 0), radial-gradient(circle 3px at 24px 12px, #ffffff 100%, transparent 0), radial-gradient(circle 3px at 12px 24px, #ffffff 100%, transparent 0);
  animation: reelSpin 4s linear infinite reverse;
}
@keyframes reelSpin { to { transform: rotate(360deg); } }
